Here are the key modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // 1. Basic async test — just return Task, MSTest awaits it
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2. [Timeout] + injected CancellationToken (MSTest v3.4+)
    //    MSTest passes a token that fires when the timeout expires.
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout(CancellationToken cancellationToken)
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("data")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Forward MSTest's timeout token into your SUT
        string result = await fetcher.FetchAsync("https://example.com", cancellationToken);

        Assert.AreEqual("data", result);
    }

    // 3. Verify that cancellation propagates correctly
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // 4. Non-success status code throws HttpRequestException
    [TestMethod]
    public async Task FetchAsync_ThrowsOnNonSuccessStatus()
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal mock — no external library needed
    private sealed class MockHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key takeaways:**

- **`async Task`** — never `async void`. MSTest awaits the task and catches exceptions properly.
- **`[Timeout]` + `CancellationToken` parameter** (MSTest v3.4+) — MSTest injects a token tied to the timeout; forward it to your SUT so the test is cancelled cleanly rather than hanging.
- **`Assert.ThrowsExactlyAsync<T>`** — the modern MSTest assertion for verifying async exceptions (unlike `ThrowsException`, it doesn't match subtypes).
- **`MockHandler`** — subclass `HttpMessageHandler` directly to avoid mocking framework dependencies; this is the standard pattern for `HttpClient` testing.
